#nullable enable // autogenerated

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Pool;

namespace MVZ2.UI.Level
{
    public class HPBarCanvasController : MonoBehaviour
    {
        private void Awake()
        {
            barItemPool = new ObjectPool<HPBarList>(BarItemCreateFunc, BarItemGetFunc, BarItemReleaseFunc, BarItemDestroyFunc);
        }

        public void AddHPBarSource(IHPBarSource source)
        {
            if (!activeHPBarItems.ContainsKey(source))
            {
                activeHPBarItems.Add(source, null);
            }
        }
        public void RemoveHPBarSource(IHPBarSource source)
        {
            if (activeHPBarItems.TryGetValue(source, out var hpBar))
            {
                if (hpBar.Exists())
                {
                    barItemPool.Release(hpBar);
                }
                activeHPBarItems.Remove(source);
            }
        }
        public void UpdateHPBars()
        {
            if (updateBuffer.Capacity < activeHPBarItems.Count)
                updateBuffer.Capacity = activeHPBarItems.Count;

            updateBuffer.Clear();
            updateBuffer.AddRange(activeHPBarItems.Keys);
            foreach (var source in updateBuffer)
            {
                if (!source.IsActive())
                {
                    if (activeHPBarItems.TryGetValue(source, out var bar) && bar.Exists())
                    {
                        barItemPool.Release(bar);
                        activeHPBarItems[source] = null;
                    }
                    continue;
                }
                if (!activeHPBarItems.TryGetValue(source, out var hpBar) || !hpBar.Exists())
                {
                    hpBar = barItemPool.Get();
                    activeHPBarItems[source] = hpBar;
                }
                hpBar.transform.position = source.GetPosition();
                var localPos = hpBar.transform.localPosition;
                localPos.z = 0;
                hpBar.transform.localPosition = localPos;
                source.UpdateHPBarList(hpBar);
            }
        }

        #region 池子
        private HPBarList BarItemCreateFunc()
        {
            return Instantiate(barItemTemplate.gameObject, Vector3.zero, Quaternion.identity, barItemRoot).GetComponent<HPBarList>();
        }
        private void BarItemGetFunc(HPBarList item)
        {
            item.gameObject.SetActive(true);
        }
        private void BarItemReleaseFunc(HPBarList item)
        {
            item.gameObject.SetActive(false);
        }
        private void BarItemDestroyFunc(HPBarList item)
        {
            Destroy(item.gameObject);
        }
        #endregion

        [SerializeField]
        private Transform barItemRoot = null!;
        [SerializeField]
        private HPBarList barItemTemplate = null!;
        private ObjectPool<HPBarList> barItemPool = null!;
        private Dictionary<IHPBarSource, HPBarList?> activeHPBarItems = new Dictionary<IHPBarSource, HPBarList?>();
        private List<IHPBarSource> updateBuffer = new List<IHPBarSource>();
    }
}
